// ========================================
// НАСТРОЙКИ КЛИНИКИ
// ========================================

// Рабочие часы клиники (Пн-Пт: 9-21, Сб: 10-18)
const workingHours = [9, 10, 11, 12, 14, 15, 16, 17, 18, 19, 20];

// Смещение часового пояса (Екатеринбург = UTC+5)
const TIMEZONE_OFFSET = 5;

// ========================================
// ОБРАБОТКА СОБЫТИЙ ИЗ GOOGLE CALENDAR
// ========================================

const busySlots = [];
const eventDetails = [];

// Получаем все события на указанную дату
const events = $input.all();

if (events && events.length > 0) {
  for (const item of events) {
    const event = item.json;

    // Проверяем, есть ли время начала события
    if (event.start && event.start.dateTime) {
      const startTime = new Date(event.start.dateTime);

      // ИСПРАВЛЕНИЕ: Берем UTC время и добавляем 5 часов вручную
      let hour = startTime.getUTCHours() + TIMEZONE_OFFSET;
      if (hour >= 24) hour -= 24;

      // Добавляем час в список занятых
      if (!busySlots.includes(hour)) {
        busySlots.push(hour);
      }

      // Сохраняем детали для отладки
      eventDetails.push({
        time: `${hour}:00`,
        title: event.summary || 'Без названия',
        utc_time: event.start.dateTime
      });
    }
  }
}

// ========================================
// ВЫЧИСЛЕНИЕ СВОБОДНЫХ СЛОТОВ
// ========================================

// Убираем занятые часы из рабочих
const availableSlots = workingHours.filter(hour => !busySlots.includes(hour));

// Форматируем для ответа
const formattedSlots = availableSlots.map(hour => (hour < 10 ? `0${hour}:00` : `${hour}:00`));
const formattedBusySlots = busySlots.map(hour => (hour < 10 ? `0${hour}:00` : `${hour}:00`));

// ========================================
// ВОЗВРАЩАЕМ РЕЗУЛЬТАТ
// ========================================

const requestBody = $('Webhook').item.json.body || {};
const requestedDate = requestBody.date || "Не указана";

return {
  json: {
    success: true,
    date: requestedDate,
    available_slots: formattedSlots,
    busy_slots: formattedBusySlots,
    debug_events: eventDetails,
    message: formattedSlots.length > 0 
      ? `На ${requestedDate} доступно ${formattedSlots.length} слотов`
      : `На ${requestedDate} нет свободных слотов`
  }
};
